values.content:
=Write a personalized cold email for this business:

Business Name: {{ $json['Business Name'] }}
Category: {{ $json['Category'] }}
Website: {{ $json['Website'] }}
Owner First Name: {{ $json['First Name'] || 'there' }}
City/Address: {{ $json['Address'] }}
Rating: {{ $json['Rating'] }}

Remember: return ONLY valid JSON with "subject" and "body" keys.

parameters.jsCode:
// Parse OpenAI response (handles markdown code blocks)
let raw = $input.first().json.text || $input.first().json.message?.content || '';

// Strip markdown code fencing if present
raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

try {
  const parsed = JSON.parse(raw);
  return [{
    json: {
      ...$input.first().json,
      email_subject: parsed.subject || 'Quick question about your business',
      email_body: parsed.body || raw,
    }
  }];
} catch (e) {
  // Fallback if JSON parse fails
  return [{
    json: {
      ...$input.first().json,
      email_subject: 'Quick question for ' + ($input.first().json['Business Name'] || 'you'),
      email_body: raw,
    }
  }];
}
